input.function:
async () => {
  window.scrollTo(0, 0);
  await new Promise(r => setTimeout(r, 2000));
  window.scrollTo(0, document.body.scrollHeight);
  await new Promise(r => setTimeout(r, 3000));

  // Get all contributor data
  const contributorLinks = document.querySelectorAll('a[href*="/commits?author="]');

  return Array.from(contributorLinks).map(a => {
    const li = a.closest('li');
    const rank = li ? li.querySelector('[aria-label*="#"]') : null;
    const rankText = li ? li.innerText.match(/#(\d+)/) : null;
    return {
      username: a.href.replace('https://github.com/facebook/react/commits?author=', ''),
      commits: a.innerText.trim(),
      rankFromText: rankText ? rankText[1] : 'unknown',
      liText: li ? li.innerText.substring(0, 100) : 'no li'
    };
  });
}

